python
playwrights = [
    {"name": "Megan Terry", "role": "premiered"},
    {"name": "Sam Shepard", "role": "premiered"},
    {"name": "Jean-Claude van Itallie", "role": "premiered"},
    {"name": "María Irene Fornés", "role": "premiered"},
    {"name": "Harold Pinter", "role": "presented"},
    {"name": "John Arden", "role": "presented"},
    {"name": "August Strindberg", "role": "presented"}
]

def categorize_playwrights(playwright_list):
    premieres = []
    presentations = []
    for playwright in playwright_list:
        if playwright["role"] == "premiered":
            premieres.append(playwright["name"])
        else:
            presentations.append(playwright["name"])
    return {"premiered": premieres, "presented": presentations}

result = categorize_playwrights(playwrights)
print(result)
